import { useState, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { adminDashboardDesign as design } from "../../design/adminDashboardDesign";

const AdminDashboard = () => {
  const adminInfo = JSON.parse(localStorage.getItem("adminInfo"));
  const [isOpen, setIsOpen] = useState(false);

  // Auto open on large screens
  useEffect(() => {
    const handleResize = () => {
      if (window.innerWidth >= 1024) {
        setIsOpen(true);
      } else {
        setIsOpen(false);
      }
    };

    handleResize();
    window.addEventListener("resize", handleResize);
    return () => window.removeEventListener("resize", handleResize);
  }, []);

  return (
    <div className={design.layout.wrapper}>

      {/* 🔥 Sidebar */}
      <AnimatePresence>
        {isOpen && (
          <motion.aside
            initial={{ x: -260 }}
            animate={{ x: 0 }}
            exit={{ x: -260 }}
            transition={{ duration: 0.3 }}
            className={`${design.colors.sidebar} ${design.layout.sidebar} fixed lg:static h-full z-50`}
          >
            <h2 className="text-2xl font-bold text-indigo-400">
              Admin Panel
            </h2>

            <nav className="space-y-3">
              <div className={`${design.layout.navItem} ${design.colors.hover}`}>
                Dashboard
              </div>
              <div className={`${design.layout.navItem} ${design.colors.hover}`}>
                Products
              </div>
              <div className={`${design.layout.navItem} ${design.colors.hover}`}>
                Orders
              </div>
              <div className={`${design.layout.navItem} ${design.colors.hover}`}>
                Users
              </div>
            </nav>
          </motion.aside>
        )}
      </AnimatePresence>

      {/* Overlay (mobile only) */}
      {isOpen && window.innerWidth < 1024 && (
        <div
          className={`fixed inset-0 ${design.colors.overlay} z-40`}
          onClick={() => setIsOpen(false)}
        />
      )}

      {/* 🔥 Right Side */}
      <div className={design.layout.rightSide}>

        {/* Navbar */}
        <div className={design.layout.navbar}>
          <button
            onClick={() => setIsOpen(!isOpen)}
            className={`lg:hidden ${design.colors.toggleBtn}`}
          >
            ☰
          </button>

          <h1 className="font-semibold text-base sm:text-lg">
            Dashboard
          </h1>

          <div className="flex items-center gap-3">
            <span className="text-xs sm:text-sm text-gray-600">
              {adminInfo?.name}
            </span>
            <div className="w-8 h-8 bg-indigo-500 rounded-full"></div>
          </div>
        </div>

        {/* Content */}
        <div className={design.layout.content}>
          <h2 className="text-2xl font-bold mb-4">
            Welcome Back 👋
          </h2>

          <p className="text-gray-600">
            Sidebar full height + top navbar aligned correctly.
          </p>
        </div>

      </div>
    </div>
  );
};

export default AdminDashboard;
